export default (n) => {
  const needed = (n.view.need ?? 0) > (n.view.got ?? 0);
  return `<!doctype html><html><head><meta charset="utf-8"><title>Larder</title>
<style>body{font-family:system-ui;max-width:28rem;margin:2rem auto;padding:0 1rem}</style></head><body>
<h1>${n.view.name ?? n.entity}</h1>
<p>${needed ? "Still needed." : "In the basket."}</p>
${needed ? `<form method="post"><input type="hidden" name="got" value="${Date.now()}"><button>Got it</button></form>` : ""}
</body></html>`;
};
